package org.rust.lang.core.mir.dataflow.move;

import org.jetbrains.annotations.NotNull;
import org.rust.lang.core.mir.WithIndex;
import org.rust.lang.core.mir.schemas.MirLocation;

/**
 * MoveOut represents a point in a program that moves out of some L-value; i.e., "creates" uninitialized memory.
 *
 * With respect to dataflow analysis:
 * - Generated by moves and declaration of uninitialized variables.
 * - Killed by assignments to the memory.
 */
public class MoveOut implements WithIndex {
    private final int index;
    @NotNull
    private final MovePath path;
    @NotNull
    private final MirLocation source;

    public MoveOut(int index, @NotNull MovePath path, @NotNull MirLocation source) {
        this.index = index;
        this.path = path;
        this.source = source;
    }

    @Override
    public int getIndex() {
        return index;
    }

    @NotNull
    public MovePath getPath() {
        return path;
    }

    @NotNull
    public MirLocation getSource() {
        return source;
    }
}
